import { NextRequest, NextResponse } from "next/server";
import { OpenAI } from "openai";

// Initialize OpenAI client pointing to xAI's API
// This runs securely on the Node.js server
const openai = new OpenAI({
  apiKey: process.env.GROK_API_KEY,
  baseURL: "https://api.x.ai/v1",
});

export async function POST(req: NextRequest) {
  try {
    const { messages } = await req.json();

    if (!messages || !Array.isArray(messages)) {
      return NextResponse.json(
        { error: "Messages array is required" },
        { status: 400 }
      );
    }

    // Call Grok API
    const response = await openai.chat.completions.create({
      model: "grok-4-1-fast-reasoning", // You can change this if the model ID changes
      messages: messages,
    });

    const aiMessage = response.choices[0]?.message;

    if (!aiMessage) {
      throw new Error("No message returned from API");
    }

    return NextResponse.json({ message: aiMessage });
  } catch (error: any) {
    console.error("Chat API Error:", error.message || error);
    return NextResponse.json(
      { error: "Failed to generate chat response" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import fs from "fs/promises";
import path from "path";

// Note: Ensure the `Beliefs` and `SliderPrompts` folders exist at the root level of your project!

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  const type = searchParams.get("type");
  const name = searchParams.get("name");
  const value = searchParams.get("value");

  if (!type) {
    return NextResponse.json({ error: "Missing type parameter" }, { status: 400 });
  }

  try {
    const rootPath = process.cwd();
    let filePath = "";

    if (type === "belief") {
      if (!value) return NextResponse.json({ error: "Missing value" }, { status: 400 });
      filePath = path.join(rootPath, "Beliefs", `${value}.txt`);
    } else if (type === "slider") {
      if (!name || !value) return NextResponse.json({ error: "Missing name or value" }, { status: 400 });
      filePath = path.join(rootPath, "SliderPrompts", name, `${value}.txt`);
    } else if (type === "template") {
      // Load the overall expression template from the Python implementation's "Prompt/expresivness.txt"
      // Wait, we need to bring Prompt/expresivness.txt over.
      filePath = path.join(rootPath, "Prompt", "expresivness.txt");
    } else {
      return NextResponse.json({ error: "Invalid type" }, { status: 400 });
    }

    // Read the file content
    const content = await fs.readFile(filePath, "utf-8");
    return NextResponse.json({ content });

  } catch (err: any) {
    if (err.code === "ENOENT") {
      return NextResponse.json({ content: "" }); // Send empty if not found, like Python gracefully handled
    }
    console.error("Error reading file:", err);
    return NextResponse.json({ error: "Failed to read file" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { ElevenLabsClient } from "elevenlabs";

// Initialize ElevenLabs on the Server Side to completely hide ELL_API_KEY
const elevenlabs = new ElevenLabsClient({
  apiKey: process.env.ELL_API_KEY,
});

export async function POST(req: NextRequest) {
  try {
    const { text, voiceId } = await req.json();

    if (!text) {
      return NextResponse.json(
        { error: "Text is required" },
        { status: 400 }
      );
    }

    // Default to the user's specific voice ID "Robert"
    const targetVoiceId = voiceId || "JBFqnCBsd6RMkjVDRZzb";

    // Call ElevenLabs
    const audioStream = await elevenlabs.textToSpeech.convert(targetVoiceId, {
      text: text,
      model_id: "eleven_multilingual_v2",
      output_format: "mp3_44100_128",
    });

    // Create a new stream response to send back the binary audio
    const readableStream = new ReadableStream({
      async start(controller) {
        try {
          for await (const chunk of audioStream) {
            controller.enqueue(chunk);
          }
          controller.close();
        } catch (streamError) {
          controller.error(streamError);
        }
      },
    });

    return new NextResponse(readableStream, {
      headers: {
        "Content-Type": "audio/mpeg",
      },
    });
  } catch (error: any) {
    console.error("TTS API Error:", error.message || error);
    return NextResponse.json(
      { error: "Failed to generate TTS" },
      { status: 500 }
    );
  }
}
